#!/usr/bin/env bash
# tails1154OS fix script - fixes Calamares on old booted live systems
set -euo pipefail

echo "==> Fixing Calamares config for tails1154OS..."

# Embedded base64-encoded tarball of config directory
B64=''

echo "$B64" | base64 -d | sudo tar xz -C /
sudo mkdir -p /root/Desktop
cat << 'EOF' | sudo tee /root/Desktop/calamares.desktop > /dev/null
[Desktop Entry]
Name=Install tails1154OS
Comment=Install tails1154OS to your computer
Exec=calamares
Icon=calamares
Terminal=false
Type=Application
Categories=Qt;System;
EOF

echo "==> Done! Calamares config restored. Run 'calamares' to start the installer."
